// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract TransferContract{
    // 接收ETH的函数需要payable修饰符
    receive() external payable { }
    // transfer方法（推荐，失败会回退）
    function transferDemo(address payable _acceptor, uint amount) public {
        (bool success, ) = _acceptor.call{value: amount}("");
        require(success, "Transfer failed");
    }
    // send方法（不推荐，需要检查返回值）
    function sendDemo(address payable _acceptor, uint amount) public returns(bool) {
    (bool suss, ) = _acceptor.call{value: amount}("");
    require(suss, "call fail");
    return suss;
    }
    // call方法（最灵活，推荐用于转账）
    function callDemo(address payable _acceptor,uint amount) public {
        (bool suss,)=_acceptor.call{value:amount}("");
        require(suss,"call fail");
    }
}

solidity-study/basic/ShopSystem.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract ShopPayment{
    address immutable public owner;
    uint public constant ITEM_PRICE = 0.1 ether;
    mapping(address => uint) public purchases;
    constructor() {
        owner = msg.sender;
    }
    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }
    // 购买商品
    function buyItem(uint quantity) public payable{
        require(msg.value == quantity * ITEM_PRICE, "Incorrect amount");
        purchases[msg.sender] += quantity;
    }
    // 查询购买数量
    function getPurchases(address buyer) public view returns (uint) {
        return purchases[buyer];
    }
    // 提现（仅owner）
    function withdraw(uint amount) public payable  onlyOwner{
        require(amount<=getContractBalance(),"No balance to withdraw");
        (bool success,)=payable(owner).call{value:amount}("");
        require(success,"Transfer fail");
    }
    // 查询合约余额
    function getContractBalance() public view returns (uint) {
        return address(this).balance;
    }
}

